### Step 2: Implement `board.py`

The `board.py` file will contain the logic for the checkerboard and its pieces.

```python
from piece import Piece

class Board:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with alternating black and white squares
        for row in range(3):
            for col in range(row % 2, 8, 2):
                self.board[row][col] = Piece(row, col, 'black')

        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece(row, col, 'white')

    def get_piece(self, row, col):
        return self.board[row][col]

    def move_piece(self, from_row, from_col, to_row, to_col):
        piece = self.get_piece(from_row, from_col)
        if piece is not None:
            self.board[from_row][from_col] = None
            self.board[to_row][to_col] = piece
            piece.set_position(to_row, to_col)

    def __str__(self):
        board_str = "  0 1 2 3 4 5 6 7\n"
        for row in range(8):
            board_str += str(row) + " "
            for col in range(8):
                piece = self.get_piece(row, col)
                if piece is None:
                    board_str += ". "
                else:
                    board_str += piece.symbol + " "
            board_str += "\n"
        return board_str
```

### Step 3: Implement `piece.py`

The `piece.py` file will contain the logic for the pieces on the board.

```python
class Piece:
    def __init__(self, row, col, color):
        self.row = row
        self.col = col
        self.color = color
        self.king = False

    def set_position(self, row, col):
        self.row = row
        self.col = col

    @property
    def symbol(self):
        return 'K' if self.king else ('b' if self.color == 'black' else 'w')

    def can_move_to(self, to_row, to_col):
        # Simple check for valid move (for now)
        return abs(to_row - self.row) == 1 and abs(to_col - self.col) == 1
```

