import sys

# Constants
BOARD_SIZE = 8
EMPTY = ' '
WHITE = 'W'
BLACK = 'B'
KING_WHITE = 'w'
KING_BLACK = 'b'

class Board:
    def __init__(self):
        self.board = [[EMPTY for _ in range(BOARD_SIZE)] for _ in range(BOARD_SIZE)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces
        for i in range(3):
            for j in range((i + 1) % 2, BOARD_SIZE, 2):
                self.board[i][j] = BLACK
        for i in range(5, BOARD_SIZE):
            for j in range((i + 1) % 2, BOARD_SIZE, 2):
                self.board[i][j] = WHITE

    def print_board(self):
        for row in self.board:
            print(' '.join(row))
        print()

    def is_valid_move(self, start, end):
        start_row, start_col = start
        end_row, end_col = end
        piece = self.board[start_row][start_col]

        if (end_row - start_row == 1 or end_row - start_row == -1) and abs(end_col - start_col) == 1:
            if end_row == BOARD_SIZE - 1 and piece == WHITE or end_row == 0 and piece == BLACK:
                return False
            target = self.board[end_row][end_col]
            if target == EMPTY:
                return True
        elif (end_row - start_row == 2 or end_row - start_row == -2) and abs(end_col - start_col) == 2:
            jump_row, jump_col = (start_row + end_row) // 2, (start_col + end_col) // 2
            target = self.board[jump_row][jump_col]
            if target in [opposite(piece), EMPTY]:
                return False

        return False

    def make_move(self, start, end):
        start_row, start_col = start
        end_row, end_col = end
        piece = self.board[start_row][start_col]

        self.board[end_row][end_col] = piece
        if end_row == BOARD_SIZE - 1 and piece == WHITE or end_row == 0 and piece == BLACK:
            self.board[end_row][end_col] = 'k' if piece.islower() else 'K'
        self.board[start_row][start_col] = EMPTY

def opposite(piece):
    return BLACK if piece == WHITE else WHITE

def main():
    board = Board()
    current_player = WHITE

    while True:
        board.print_board()
        start = input(f"Player {current_player}, enter your move (e.g., 2 1): ").split()
        end = input(f"Player {current_player}, enter your destination (e.g., 4 3): ").split()

        if len(start) != 2 or len(end) != 2:
            print("Invalid input. Please enter two pairs of coordinates.")
            continue

        start_row, start_col = int(start[0]), int(start[1])
        end_row, end_col = int(end[0]), int(end[1])

        if not (0 <= start_row < BOARD_SIZE and 0 <= start_col < BOARD_SIZE):
            print("Invalid starting position.")
            continue

        if not (0 <= end_row < BOARD_SIZE and 0 <= end_col < BOARD_SIZE):
            print("Invalid ending position.")
            continue

        if board.is_valid_move((start_row, start_col), (end_row, end_col)):
            board.make_move((start_row, start_col), (end_row, end_col))
            current_player = opposite(current_player)
        else:
            print("Invalid move. Try again.")

if __name__ == "__main__":
    main()
```

